function initMultiTextFieldPicker(e){if(e){var t=e.id,n=JSON.parse(e.dataset.selectedvalues||"[]"),u=JSON.parse(e.dataset.options||"[]"),i=Vue.component("vue-multiselect",window.VueMultiselect.default),a=new CustomEvent("multitextfield-picker-created",{detail:{vm:new Vue({el:"#"+t,components:{"vue-multiselect":i},data:function(){return{value:n,options:u,valuesKey:e.dataset.valueskey}},watch:{value:function(){setTimeout(function(){$(document).trigger("contentpreview:render")},100)}}})}});document.querySelector("body").dispatchEvent(a)}}
